SELECT COUNT(*) AS active_hooks_count
FROM hooks
WHERE is_active = 1;

SELECT hook_name
FROM hooks
WHERE is_active = 1 AND priority > 5;

SELECT hook_id
FROM hooks
WHERE hook_id = 1;

SELECT hook_name, COUNT(*) AS hook_count
FROM hooks
GROUP BY hook_name;

SELECT COUNT(hu.hook_id) AS num_hooks_used
FROM hook_usage hu
WHERE hu.developer_id = 1 AND hu.environment = 'production';
